import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import {
  Container,
  Typography,
  Box,
  AppBar,
  Toolbar,
  Button,
  Pagination,
  Card,
  CardMedia,
  CardContent,
} from "@mui/material";

import "./BoardPage.css";

function BoardPage() {

  const navigate = useNavigate();

  // 임시 데이터 (나중에 DB 연결)
  const posts = [
    { id: 1, title: "노트북 분실", image: "/waiting.png" },
    { id: 2, title: "지갑 발견", image: "/waiting.png" },
    { id: 3, title: "에어팟 찾음", image: "/waiting.png" },
    { id: 1, title: "노트북 분실", image: "/waiting.png" },
    { id: 2, title: "지갑 발견", image: "/waiting.png" },
    { id: 3, title: "에어팟 찾음", image: "/waiting.png" },
    { id: 1, title: "노트북 분실", image: "/waiting.png" },
    { id: 2, title: "지갑 발견", image: "/waiting.png" },
    { id: 3, title: "에어팟 찾음", image: "/waiting.png" },
    { id: 1, title: "노트북 분실", image: "/waiting.png" },
    { id: 2, title: "지갑 발견", image: "/waiting.png" },
    { id: 3, title: "에어팟 찾음", image: "/waiting.png" },
  ];

  const [page, setPage] = useState(1);
  const pageSize = 9;

  const handleChange = (e, value) => {
    setPage(value);
  };

  const start = (page - 1) * pageSize;

  const currentPosts = posts.slice(start, start + pageSize);

// =========================
// 로그인 확인
// =========================
useEffect(() => {

  const verifyUser = async () => {

    const token = localStorage.getItem("token");

    // 토큰 없으면 차단
    if (!token) {

      navigate("/");

      return;
    }

    try {

      const response = await fetch(
        "http://127.0.0.1:5000/profile",
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      );

      // 토큰 만료 / 로그아웃됨
      if (!response.ok) {

        localStorage.removeItem("token");

        navigate("/");
      }

    } catch (error) {

      navigate("/");
    }
  };

  verifyUser();

}, []);

// =========================
// 로그아웃
// =========================
const handleLogout = async () => {

  const token = localStorage.getItem("token");

  try {

    await fetch(
      "http://127.0.0.1:5000/logout",
      {
        method: "POST",

        headers: {
          Authorization: `Bearer ${token}`,
        },
      }
    );

  } catch (error) {

    console.log(error);
  }

  // 프론트 토큰 삭제
  localStorage.removeItem("token");

  // 로그인 페이지 이동
  navigate("/");
};

  return (
    <>
      {/* Navbar */}
      <AppBar position="static" className="navbar">

        <Toolbar className="navbar-toolbar">

          <img
            src="/kw_logo.png"
            className="navbar-logo"
            alt="logo"
          />

          <Box sx={{ marginLeft: "auto" }}>

            <Button className="nav-button">검색</Button>

            <Button
              className="nav-button"
              onClick={() => navigate("/create")}
            >
              게시물 등록
            </Button>

            <Button className="nav-button logout-btn">
              로그아웃
            </Button>

          </Box>

        </Toolbar>

      </AppBar>

      {/* 배너 */}
      <Box className="board-header">
        <Typography variant="h4">
          게시판
        </Typography>
      </Box>

      {/* 카드 게시판 */}
      <Container>

        <Box className="card-grid">

          {currentPosts.map((post) => (
            <Card key={post.id} className="post-card">

              <CardMedia
                component="img"
                image={post.image}
                className="post-image"
              />

              <CardContent className="post-title-box">
                <Typography className="post-title">
                  {post.title}
                </Typography>
              </CardContent>

            </Card>
          ))}

        </Box>

        {/* 페이지네이션 */}
        <Box sx={{ display: "flex", justifyContent: "center", mt: 3 }}>
          <Pagination
            count={Math.ceil(posts.length / pageSize) || 1}
            page={page}
            onChange={handleChange}
            color="primary"
          />
        </Box>

      </Container>
    </>
  );
}

export default BoardPage;
